import { readFile, writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import prettier from "prettier";

const projectRoot = dirname(dirname(fileURLToPath(import.meta.url)));
const generatedBanner =
  "<!-- Generated by Next.js static export. Edit app/ source files and run npm run build:github. -->";
const htmlFiles = ["index.html", "404.html"];

function normalizeGeneratedHtml(source) {
  let html = source.trim();

  if (!html.startsWith("<!-- Generated by Next.js")) {
    html = `${generatedBanner}\n${html}`;
  }

  html = html.replaceAll("charSet=", "charset=");

  html = html.replace(
    /<script>([\s\S]*?)<\/script>/g,
    (match, scriptBody) => {
      if (!scriptBody.includes("__next_f")) {
        return match;
      }

      if (scriptBody.includes("@ts-nocheck")) {
        return match;
      }

      return `<script>// @ts-nocheck\n${scriptBody}</script>`;
    }
  );

  return html;
}

for (const fileName of htmlFiles) {
  const filePath = join(projectRoot, fileName);

  try {
    const source = await readFile(filePath, "utf8");
    const normalized = normalizeGeneratedHtml(source);
    const formatted = await prettier.format(normalized, {
      parser: "html",
      printWidth: 100,
      tabWidth: 2,
      useTabs: false,
      htmlWhitespaceSensitivity: "ignore"
    });

    await writeFile(filePath, formatted, "utf8");
    console.log(`Formatted ${fileName}`);
  } catch (error) {
    if (error && typeof error === "object" && "code" in error && error.code === "ENOENT") {
      console.warn(`Skipped missing file: ${fileName}`);
      continue;
    }

    throw error;
  }
}
